FROM member_history
WHERE changed_field = 'chamber_id';

external_knowledge:
- "Grand chambers of governance" refers to the legislative bodies, such as the House and Senate;
- "Share of the pie" is a metaphor for the proportion or percentage of something;
- "Secured" in this context means the votes that were won in the elections.

sql:
SELECT COUNT(member_id) 
FROM members 
WHERE party_id = (SELECT party_id FROM parties WHERE party_abbrev = 'R');

external_knowledge:
- "Cumulative votes" refer to the total votes a member has received over their terms in the same chamber and state.;
- "Chamber" refers to the legislative body, such as the House or Senate.;
- "State" refers to the U.S. state the member represents.;

- "Blooming" refers to participating in at least one election;
- "Political garden" is a metaphor for the legislative body or chamber;
- "Representatives" are the members of the legislative body.

- 'Tasted the sweet nectar of victory' refers to winning the election;
- 'Shining stars' refers to members with notable performance;
- 'Blossomed above the 50% mark' refers to an average voter turnout greater than 50%.

sql:
SELECT COUNT(member_id) AS num_members
FROM fec_candidates
WHERE fec_cand_name = 'Bradley Byrne';

SELECT MAX(avg_members_per_party) AS max_avg_members_per_party
FROM (
  SELECT chamber_id, AVG(member_count) AS avg_members_per_party
  FROM (
    SELECT chamber_id, party_id, COUNT(member_id) AS member_count
    FROM members
    GROUP BY chamber_id, party_id
  ) AS subquery
  GROUP BY chamber_id
) AS avg_per_chamber;

external_knowledge:
- 'House chamber' refers to the House of Representatives in the U.S. Congress;
- 'state_abbrev' is the two-letter abbreviation for the state, where 'AK' stands for Alaska;
- 'last_name' refers to the surname of the member.
